+        .args(["-c", &script])
+        .output()
+        .expect("python3 chmod JSON");
+    assert!(
+        out.status.success(),
+        "python3 chmod JSON helper failed: {}",
+        String::from_utf8_lossy(&out.stderr)
+    );
+    serde_json::from_slice(&out.stdout).expect("parse chmod JSON")
+}
